#include <stdio.h>

struct Pravougaonik {
    int sirina;
    int visina;
};

/* Funkcija prima strukturu i vraca novu strukturu */
struct Pravougaonik povecaj_pravougaonik(struct Pravougaonik p) {
    p.sirina += 1;
    return p;
}

int main(void) {
    struct Pravougaonik p1 = {4, 3};
    struct Pravougaonik p2;

    p2 = povecaj_pravougaonik(p1);

    printf("Povecani pravougaonik: %d x %d\n", p2.sirina, p2.visina);
    return 0;
}
